// ── DÉCOUPAGE EN CHUNKS ──────────────────────────────────
const MOTS_MAX = 500;    // Taille max d'un chunk en mots
const MOTS_MIN = 50;     // Taille min (ignore les chunks trop courts)

const sections = [];
const lines = markdown.split('\n');
let currentChunk = [];
let currentTitle = 'Introduction';
let wordCount = 0;
let chunkIndex = 0;

for (const line of lines) {
  const isTitle = line.startsWith('# ') || line.startsWith('## ');

  if (isTitle && currentChunk.length > 0) {
    // Sauvegarde le chunk actuel si assez grand
    const content = currentChunk.join('\n').trim();
    const words = content.split(/\s+/).length;

    if (words >= MOTS_MIN) {
      chunkIndex++;
      sections.push({
        index: chunkIndex,
        titre: currentTitle,
        contenu: content,
        mots: words
      });
      console.log(`📦 Chunk ${chunkIndex}: "${currentTitle}" — ${words} mots`);
    } else {
      console.log(`⏭️ Chunk ignoré (trop court): "${currentTitle}" — ${words} mots`);
    }

    // Nouveau chunk
    currentTitle = line.replace(/^#+\s/, '').trim();
    currentChunk = [line];
    wordCount = 0;

  } else {
    currentChunk.push(line);
    wordCount += line.split(/\s+/).filter(w => w.length > 0).length;

    // Coupe si trop long
    if (wordCount >= MOTS_MAX) {
      const content = currentChunk.join('\n').trim();
      chunkIndex++;
      sections.push({
        index: chunkIndex,
        titre: currentTitle + ` (partie ${Math.ceil(chunkIndex)})`,
        contenu: content,
        mots: wordCount
      });
      console.log(`📦 Chunk ${chunkIndex} (coupé): "${currentTitle}" — ${wordCount} mots`);
      currentChunk = [];
      wordCount = 0;
    }
  }
}

// Dernier chunk
if (currentChunk.length > 0) {
  const content = currentChunk.join('\n').trim();
  const words = content.split(/\s+/).length;
  if (words >= MOTS_MIN) {
    chunkIndex++;
    sections.push({
      index: chunkIndex,
      titre: currentTitle,
      contenu: content,
      mots: words
    });
  }
}

console.log(`\n🎯 Total: ${sections.length} chunks générés sur ${chunkIndex} tentatives`);
console.log(`📊 Mots moyens par chunk: ${Math.round(sections.reduce((a,s) => a+s.mots, 0) / sections.length)}`);

// Retourne chaque chunk comme un item séparé
return sections.map(s => ({ json: s }));

