/**
 * NŒUD 5b — Préparation de l'Upsert Flowise
 * 
 * But : Parser la réponse DeepSeek et assembler
 *       le payload pour l'upsert dans Chroma.
 * 
 * Gestion d'erreur : si le JSON DeepSeek est invalide,
 * utilise des métadonnées génériques pour ne pas bloquer.
 */

const deepseekResponse = $input.first().json;

// Récupère le chunk original depuis le nœud précédent
// (on passe par $('nom-noeud') pour accéder aux données du bon nœud)
let chunk;
try {
  chunk = $('✂️ HTML→Markdown + Chunks').first().json;
} catch(e) {
  console.log('⚠️ Impossible de récupérer le chunk original:', e.message);
  chunk = { titre: 'Inconnu', contenu: '', mots: 0, index: 0 };
}

console.log(`\n🔍 Traitement chunk #${chunk.index}: "${chunk.titre}"`);

// ── PARSE MÉTADONNÉES DEEPSEEK ───────────────────────────
let metadata = {};
let parseSuccess = false;

try {
  const content = deepseekResponse?.choices?.[0]?.message?.content || '';
  console.log('📤 Réponse DeepSeek brute:', content.substring(0, 200));

  // Nettoie le JSON (supprime markdown si présent)
  const cleaned = content
    .replace(/```json\s*/gi, '')
    .replace(/```\s*/gi, '')
    .trim();

  metadata = JSON.parse(cleaned);
  parseSuccess = true;
  console.log('✅ Métadonnées parsées:', JSON.stringify(metadata));

} catch(e) {
  // Fallback : métadonnées génériques si parsing échoue
  console.log('⚠️ Parsing JSON échoué, utilisation des métadonnées par défaut:', e.message);
  metadata = {
    module: 'general',
    sous_theme: 'non_classe',
    difficulte: 'debutant',
    type: 'principe',
    source: 'Big Al',
    tags: ['mlm', 'formation'],
    resume: chunk.titre.substring(0, 100)
  };
}

// ── ASSEMBLAGE DU PAYLOAD FLOWISE ───────────────────────
const payload = {
  // Texte du chunk en Markdown
  text: chunk.contenu,

  // Métadonnées enrichies
  metadata: {
    // Métadonnées générées par DeepSeek
    ...metadata,

    // Métadonnées techniques
    titre: chunk.titre,
    chunk_index: chunk.index,
    mots: chunk.mots,
    langue: 'fr',
    parse_success: parseSuccess,

    // Timestamps
    indexed_at: new Date().toISOString(),
    source_file: 'big_al_happy_network'
  }
};

console.log(`\n📦 Payload prêt pour Flowise:`);
console.log(`   Texte: ${payload.text.length} caractères`);
console.log(`   Module: ${payload.metadata.module}`);
console.log(`   Tags: ${payload.metadata.tags?.join(', ')}`);

return [{ json: payload }];
